#include <iostream>

int main() {
  int score = 85;
  if (score >= 90) {
    std::cout << "Grade: A" << std::endl;
  } else if (score >= 80) {
    std::cout << "Grade: B" << std::endl;
  } else if (score >= 70) {
    std::cout << "Grade: C" << std::endl;
  }
  return 0;
}
// Output:
// Grade: B

#include <iostream>

int main() {
  int number = -5;
  if (number > 0) {
    std::cout << "Number is positive" << std::endl;
  } else if (number < 0) {
    std::cout << "Number is negative" << std::endl;
  } else {
    std::cout << "Number is zero" << std::endl;
  }
  return 0;
}
// Output:
// Number is negative

#include <iostream>

int main() {
  int age = 15;
  int ticketPrice = 20;
  if (age < 18) {
    if (ticketPrice <= 25) {
      std::cout << "Discounted ticket for minor" << std::endl;
    } else {
      std::cout << "Standard ticket for minor" << std::endl;
    }
  } else {
    std::cout << "Adult ticket" << std::endl;
  }
  return 0;
}
// Output:
// Discounted ticket for minor

